import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

/**
 * Utility class for computing message digests (hash values) of file contents.
 * Provides a secure and efficient way to generate SHA-256 hash values.
 */
public class HashService {

    /**
     * Computes the SHA-256 message digest of the given byte array.
     *
     * @param data the byte array representing the file content
     * @return a hexadecimal string representation of the SHA-256 hash value
     * @throws RuntimeException if the SHA-256 algorithm is not supported (should not happen in standard JVMs)
     */
    public String digest(byte[] data) {
        try {
            // Use SHA-256 algorithm which provides strong security
            MessageDigest digest = MessageDigest.getInstance("SHA-256");

            // Compute the hash
            byte[] hashBytes = digest.digest(data);

            // Convert byte array to hexadecimal string
            StringBuilder hexString = new StringBuilder(64);
            for (byte b : hashBytes) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) {
                    hexString.append('0');
                }
                hexString.append(hex);
            }
            return hexString.toString();

        } catch (NoSuchAlgorithmException e) {
            // SHA-256 is part of the Java standard library and should always be available
            // If it's not available, something is seriously wrong with the JVM
            throw new RuntimeException("SHA-256 algorithm not available", e);
        }
    }
}

